const runId = new Date().toISOString();
const runIdSafe = runId.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '');
const queueName = `test_queue_${runIdSafe.slice(0, 24)}`;
const workerId = `test_worker_${runIdSafe.slice(0, 24)}`;
const workerName = `Test Worker ${runId}`;

const context = {
  run_id: runId,
  subworkflow_id: 'O_tR9X8q-2HpncmSGgqIS',
  fallback_api_key: 'REPLACE_WITH_WORKER_API_KEY',
  queue_name: queueName,
  worker_id: workerId,
  worker_name: workerName,
  api_key: null,
  task_uuid_1: null,
  task_uuid_2: null,
  task_id_1: null,
  task_id_2: null,
  results: []
};

return [{
  json: {
    context,
    call: 'create_queue',
    args: {
      queue_name: queueName,
      description: `Test queue for run ${runId}`
    }
  }
}];

const prev = $items('Init Test Context')[0].json.context;
const result = $input.all()[0]?.json ?? {};
const ok = result.create_queue === true || result.create_queue === 't' || result.create_queue === 1;
const error = result.error || result.message || null;

const testResult = {
  name: 'create_queue',
  success: ok && !error,
  expected: 'create_queue returns true',
  actual: result,
  error
};

const context = { ...prev, results: [...prev.results, testResult] };

return [{
  json: {
    context,
    call: 'register_worker',
    args: {
      worker_id: context.worker_id,
      worker_name: context.worker_name,
      max_concurrent_tasks: 3,
      heartbeat_interval: '30 seconds',
      subscribed_queues: ['default', context.queue_name]
    }
  }
}];

const prev = $items('After Create Queue')[0].json.context;
const result = $input.all()[0]?.json ?? {};

let apiKey = result.api_key;
if (!apiKey && typeof result.register_worker === 'string') {
  const match = result.register_worker.match(/sk_[a-zA-Z0-9]+/);
  if (match) apiKey = match[0];
}

const usedApiKey = apiKey || prev.fallback_api_key || null;
const ok = !!apiKey;
const error = result.error || result.message || null;

const testResult = {
  name: 'register_worker',
  success: ok && !error,
  expected: 'api_key returned from register_worker',
  actual: result,
  error,
  api_key_source: apiKey ? 'register_worker' : 'fallback'
};

const context = { ...prev, api_key: usedApiKey, results: [...prev.results, testResult] };

return [{
  json: {
    context,
    call: 'update_worker_subscriptions',
    args: {
      api_key: context.api_key,
      subscribed_queues: ['default', context.queue_name, 'email']
    }
  }
}];

const prev = $items('After Register Worker')[0].json.context;
const result = $input.all()[0]?.json ?? {};
const ok = result.update_worker_subscriptions === true || result.update_worker_subscriptions === 't' || result.update_worker_subscriptions === 1;
const error = result.error || result.message || null;

const testResult = {
  name: 'update_worker_subscriptions',
  success: ok && !error,
  expected: 'update_worker_subscriptions returns true',
  actual: result,
  error
};

const context = { ...prev, results: [...prev.results, testResult] };

return [{
  json: {
    context,
    call: 'enqueue_task',
    args: {
      api_key: context.api_key,
      task_name: `test_task_success_${context.run_id}`,
      task_data: { run_id: context.run_id, test: 'enqueue_task_1' },
      queue_name: context.queue_name,
      priority: 10
    }
  }
}];

const prev = $items('After Update Subscriptions')[0].json.context;
const result = $input.all()[0]?.json ?? {};
const taskUuid = result.enqueue_task || result.task_uuid || null;
const ok = typeof taskUuid === 'string' && taskUuid.length >= 10;
const error = result.error || result.message || null;

const testResult = {
  name: 'enqueue_task',
  success: ok && !error,
  expected: 'enqueue_task returns uuid',
  actual: result,
  error
};

const context = { ...prev, task_uuid_1: taskUuid, results: [...prev.results, testResult] };

return [{
  json: {
    context,
    call: 'dequeue_task',
    args: {
      api_key: context.api_key,
      lease_duration: '5 minutes',
      queue_names: [context.queue_name]
    }
  }
}];

const prev = $items('After Enqueue Task 1')[0].json.context;
const result = $input.all()[0]?.json ?? {};
const taskId = result.task_id || result.id || null;
const ok = typeof taskId === 'number' || (typeof taskId === 'string' && taskId !== '');
const error = result.error || result.message || null;

const testResult = {
  name: 'dequeue_task',
  success: ok && !error,
  expected: 'dequeue_task returns task_id',
  actual: result,
  error
};

const context = { ...prev, task_id_1: taskId, results: [...prev.results, testResult] };

return [{
  json: {
    context,
    call: 'complete_task',
    args: {
      api_key: context.api_key,
      task_id: context.task_id_1,
      result_data: { status: 'success', run_id: context.run_id }
    }
  }
}];

const prev = $items('After Dequeue Task 1')[0].json.context;
const result = $input.all()[0]?.json ?? {};
const ok = result.complete_task === true || result.complete_task === 't' || result.complete_task === 1;
const error = result.error || result.message || null;

const testResult = {
  name: 'complete_task',
  success: ok && !error,
  expected: 'complete_task returns true',
  actual: result,
  error
};

const context = { ...prev, results: [...prev.results, testResult] };

return [{
  json: {
    context,
    call: 'enqueue_task',
    args: {
      api_key: context.api_key,
      task_name: `test_task_fail_${context.run_id}`,
      task_data: { run_id: context.run_id, test: 'enqueue_task_2' },
      queue_name: context.queue_name,
      priority: 5
    }
  }
}];

const prev = $items('After Complete Task')[0].json.context;
const result = $input.all()[0]?.json ?? {};
const taskUuid = result.enqueue_task || result.task_uuid || null;
const ok = typeof taskUuid === 'string' && taskUuid.length >= 10;
const error = result.error || result.message || null;

const testResult = {
  name: 'enqueue_task_2',
  success: ok && !error,
  expected: 'enqueue_task returns uuid (second task)',
  actual: result,
  error
};

const context = { ...prev, task_uuid_2: taskUuid, results: [...prev.results, testResult] };

return [{
  json: {
    context,
    call: 'dequeue_task',
    args: {
      api_key: context.api_key,
      lease_duration: '5 minutes',
      queue_names: [context.queue_name]
    }
  }
}];

const prev = $items('After Enqueue Task 2')[0].json.context;
const result = $input.all()[0]?.json ?? {};
const taskId = result.task_id || result.id || null;
const ok = typeof taskId === 'number' || (typeof taskId === 'string' && taskId !== '');
const error = result.error || result.message || null;

const testResult = {
  name: 'dequeue_task_2',
  success: ok && !error,
  expected: 'dequeue_task returns task_id (second task)',
  actual: result,
  error
};

const context = { ...prev, task_id_2: taskId, results: [...prev.results, testResult] };

return [{
  json: {
    context,
    call: 'fail_task',
    args: {
      api_key: context.api_key,
      task_id: context.task_id_2,
      error_message: 'Intentional failure for test coverage',
      retry: true
    }
  }
}];

const prev = $items('After Dequeue Task 2')[0].json.context;
const result = $input.all()[0]?.json ?? {};
const ok = result.fail_task === true || result.fail_task === 't' || result.fail_task === 1;
const error = result.error || result.message || null;

const testResult = {
  name: 'fail_task',
  success: ok && !error,
  expected: 'fail_task returns true',
  actual: result,
  error
};

const context = { ...prev, results: [...prev.results, testResult] };

return [{
  json: {
    context,
    call: 'heartbeat',
    args: {
      api_key: context.api_key,
      current_load: 0
    }
  }
}];

const prev = $items('After Fail Task')[0].json.context;
const result = $input.all()[0]?.json ?? {};
const ok = result.worker_heartbeat === true || result.worker_heartbeat === 't' || result.worker_heartbeat === 1;
const error = result.error || result.message || null;

const testResult = {
  name: 'worker_heartbeat',
  success: ok && !error,
  expected: 'worker_heartbeat returns true',
  actual: result,
  error
};

const context = { ...prev, results: [...prev.results, testResult] };

return [{
  json: {
    context,
    call: 'get_task_status',
    args: {
      api_key: context.api_key,
      task_id: context.task_id_1
    }
  }
}];

const prev = $items('After Worker Heartbeat')[0].json.context;
const result = $input.all()[0]?.json ?? {};
const ok = !!(result.status || result.task_uuid || result.id || result.task_id || result.get_task_status);
const error = result.error || result.message || null;

const testResult = {
  name: 'get_task_status',
  success: ok && !error,
  expected: 'task status record returned',
  actual: result,
  error
};

const context = { ...prev, results: [...prev.results, testResult] };

return [{
  json: {
    context,
    call: 'get_queue_stats',
    args: {}
  }
}];

const prev = $items('After Get Task Status')[0].json.context;
const items = $input.all();
const queueNames = items.map(i => i.json.queue_name).filter(Boolean);
const ok = queueNames.length > 0;
const error = items[0]?.json?.error || items[0]?.json?.message || null;

const testResult = {
  name: 'get_queue_stats',
  success: ok && !error,
  expected: 'queue stats returned',
  actual: items.map(i => i.json),
  error
};

const context = { ...prev, results: [...prev.results, testResult] };

return [{
  json: {
    context,
    call: '',
    args: {}
  }
}];

const prev = $items('After Get Queue Stats')[0].json.context;
const result = $input.all()[0]?.json ?? {};
const ok = result.success === false && String(result.error || '').toLowerCase().includes('invalid');
const error = result.error || result.message || null;

const testResult = {
  name: 'missing_call',
  success: ok,
  expected: 'error response for missing call',
  actual: result,
  error
};

const results = [...prev.results, testResult];
const passed = results.filter(r => r.success).length;
const failed = results.length - passed;

return [{
  json: {
    run_id: prev.run_id,
    queue_name: prev.queue_name,
    worker_id: prev.worker_id,
    api_key_prefix: prev.api_key ? String(prev.api_key).slice(0, 10) : null,
    summary: {
      total: results.length,
      passed,
      failed
    },
    results
  }
}];
